#include <iostream>
#include <fstream>
#include <string>

int main() {
    std::ifstream f("hello.txt");
    if (!f.is_open()) {
        std::cerr << "Error: cannot open file" << std::endl;
        return 1;
    }
    std::string line;
    while (std::getline(f, line)) {
        std::cout << line << std::endl;
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::vector<int> v = {5, 3, 1, 4, 2};
    std::sort(v.begin(), v.end());
    for (int i = 0; i < v.size(); i++) {
        std::cout << v[i];
        if (i < (int)v.size() - 1) std::cout << ", ";
    }
    std::cout << std::endl;

    // Test C++20 features
    auto sum = std::accumulate(v.begin(), v.end(), 0);
    std::cout << "Sum: " << sum << std::endl;
    return 0;
}

#include <iostream>
#include <string>
#include <map>

class Animal {
public:
    virtual std::string speak() const = 0;
    virtual ~Animal() = default;
};

class Dog : public Animal {
public:
    std::string speak() const override { return "Woof!"; }
};

class Cat : public Animal {
public:
    std::string speak() const override { return "Meow!"; }
};

int main() {
    std::map<std::string, Animal*> animals;
    Dog dog;
    Cat cat;
    animals["dog"] = &dog;
    animals["cat"] = &cat;

    for (auto& [name, animal] : animals) {
        std::cout << name << ": " << animal->speak() << std::endl;
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <cmath>

int main() {
    std::vector<double> values = {1.5, 2.5, 3.5, 4.5, 5.5};

    double sum = std::accumulate(values.begin(), values.end(), 0.0);
    double mean = sum / values.size();

    double sq_sum = 0;
    for (double v : values) {
        sq_sum += std::pow(v - mean, 2);
    }
    double stddev = std::sqrt(sq_sum / values.size());

    std::cout << "Mean: " << mean << std::endl;
    std::cout << "StdDev: " << stddev << std::endl;
    return 0;
}

#include <iostream>
#include <thread>
#include <mutex>

std::mutex mtx;
int counter = 0;

void increment() {
    for (int i = 0; i < 1000; i++) {
        std::lock_guard<std::mutex> lock(mtx);
        counter++;
    }
}

int main() {
    std::thread t1(increment);
    std::thread t2(increment);
    t1.join();
    t2.join();
    std::cout << "Counter: " << counter << std::endl;
    return 0;
}
